SELECT
FROM T_STOCK_DIVIDEND_CONFIRMED TSDC LEFT JOIN M_STOCK MS ON TSDC.STOCK_CODE = MS.STOCK_CODE
(MS.TYPE_CODE IS NULL OR MS.TYPE_CODE <> '9999')
AND TSDC.STOCK_CODE = #{stockCode}
AND TSDC.RIGHTS_LAST_DAY = #{rightsLastDay}
AND TSDC.RECORD_DATE >= #{recordDateFrom}
AND TSDC.RECORD_DATE <= #{recordDateTo}
AND TSDC.CONFIRMED_FLG = #{confirmedFlg}
ORDER BY
TSDC.ID TSDC.STOCK_CODE MS.TYPE_NAME TSDC.DIVIDEND_YIELD TSDC.RIGHTS_LAST_DAY TSDC.RECORD_DATE
ASC DESC , TSDC.ID DESC LIMIT #{limit} OFFSET #{offset}

SELECT
    COUNT(1)
FROM T_STOCK_DIVIDEND_CONFIRMED TSDC
LEFT JOIN M_STOCK MS ON TSDC.STOCK_CODE = MS.STOCK_CODE

    (MS.TYPE_CODE IS NULL OR MS.TYPE_CODE <> '9999')

        AND TSDC.STOCK_CODE = #{stockCode}


        AND TSDC.RIGHTS_LAST_DAY = #{rightsLastDay}


        AND TSDC.RECORD_DATE >= #{recordDateFrom}


        AND TSDC.RECORD_DATE <= #{recordDateTo}


        AND TSDC.CONFIRMED_FLG = #{confirmedFlg}

SELECT

FROM T_STOCK_DIVIDEND_CONFIRMED TSDC
LEFT JOIN M_STOCK MS ON TSDC.STOCK_CODE = MS.STOCK_CODE
WHERE TSDC.STOCK_CODE = #{stockCode}
  AND TSDC.RECORD_DATE = #{recordDate}

